mapper.update:
UPDATE post
SET title = #{title}, content = #{content}, cover_image = #{coverImage}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

mapper.select:
SELECT p.id, p.title, COALESCE(m.nickname, '탈퇴한 사용자') AS authorNickname, p.view_count AS viewCount, p.like_count AS likeCount, , p.created_at AS createdAt, false AS liked,
FROM post p LEFT JOIN member m ON m.id = p.member_id
WHERE p.member_id = #{memberId} AND p.deleted_at IS NULL ORDER BY p.created_at DESC LIMIT #{limit} OFFSET #{offset}
